queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPerformances ?child ; p:hasCultural_Centers ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cultural_Centers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?type WHERE {
  ?cultural_centers_performances a :Cultural_Centers_Performances .
  ?performances a :Performances .
  ?cultural_centers_performances p:hasPerformances ?performances .
  ?cultural_centers a :Cultural_Centers .
  ?cultural_centers_performances p:hasCultural_Centers ?cultural_centers .
  ?cultural_centers p:name ?name .
  ?performances p:type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPerformances ?child ; p:hasCultural_Centers ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cultural_Centers } }
  FILTER(?nf = ?total)
} }
}
